1	const GraficoTendencia = {
2	  template: `
3	    <div class="w-full">
4	      <canvas id="graficoTendencia" height="80"></canvas>
5	    </div>
6	  `,
7	  data() {
8	    return {
9	      chart: null,
10	      periodo: {
11	        dataInicio: this.obterDataInicio(),
12	        dataFim: this.obterDataFim()
13	      }
14	    };
15	  },
16	  watch: {
17	    periodo: {
18	      handler() {
19	        this.carregarDadosGrafico();
20	      },
21	      deep: true
22	    }
23	  },
24	  methods: {
25	    obterDataInicio() {
26	      const hoje = new Date();
27	      const inicio = new Date(hoje.getTime() - 30 * 24 * 60 * 60 * 1000);
28	      return inicio.toISOString().split('T')[0];
29	    },
30	    obterDataFim() {
31	      const hoje = new Date();
32	      return hoje.toISOString().split('T')[0];
33	    },
34	    async carregarDadosGrafico() {
35	      try {
36	        const response = await api.obterDadosGrafico(this.periodo.dataInicio, this.periodo.dataFim);
37	        if (response.data.success) {
38	          const dados = response.data.data;
39	
40	          // Preparar dados para gráfico
41	          const labels = dados.map(d => this.formatarData(d.data));
42	          const valores = dados.map(d => parseFloat(d.total));
43	
44	          this.renderizarGrafico(labels, valores);
45	        }
46	      } catch (error) {
47	        console.error('Erro ao carregar dados do gráfico:', error);
48	      }
49	    },
50	    renderizarGrafico(labels, valores) {
51	      const canvas = document.getElementById('graficoTendencia');
52	      if (!canvas) return;
53	
54	      // Destruir gráfico anterior se existir
55	      if (this.chart) {
56	        this.chart.destroy();
57	      }
58	
59	      const ctx = canvas.getContext('2d');
60	      this.chart = new Chart(ctx, {
61	        type: 'line',
62	        data: {
63	          labels: labels,
64	          datasets: [
65	            {
66	              label: 'Faturamento Diário (R$)',
67	              data: valores,
68	              borderColor: '#3b82f6',
69	              backgroundColor: 'rgba(59, 130, 246, 0.1)',
70	              tension: 0.4,
71	              fill: true,
72	              pointRadius: 4,
73	              pointBackgroundColor: '#3b82f6',
74	              pointBorderColor: '#fff',
75	              pointBorderWidth: 2,
76	              pointHoverRadius: 6
77	            }
78	          ]
79	        },
80	        options: {
81	          responsive: true,
82	          maintainAspectRatio: true,
83	          plugins: {
84	            legend: {
85	              display: true,
86	              position: 'top'
87	            },
88	            tooltip: {
89	              callbacks: {
90	                label: function(context) {
91	                  return `R$ ${context.parsed.y.toLocaleString('pt-BR', {
92	                    minimumFractionDigits: 2,
93	                    maximumFractionDigits: 2
94	                  })}`;
95	                }
96	              }
97	            }
98	          },
99	          scales: {
100	            y: {
101	              beginAtZero: true,
102	              ticks: {
103	                callback: function(value) {
104	                  return 'R$ ' + value.toLocaleString('pt-BR', {
105	                    minimumFractionDigits: 0,
106	                    maximumFractionDigits: 0
107	                  });
108	                }
109	              }
110	            }
111	          }
112	        }
113	      });
114	    },
115	    formatarData(data) {
116	      const opcoes = { month: '2-digit', day: '2-digit' };
117	      return new Date(data).toLocaleDateString('pt-BR', opcoes);
118	    },
119	    atualizarGrafico(periodo) {
120	      if (periodo) {
121	        this.periodo = periodo;
122	      }
123	      this.carregarDadosGrafico();
124	    }
125	  },
126	  mounted() {
127	    this.carregarDadosGrafico();
128	  }
129	};
